import json

def validate_action_group_response(response: dict) -> bool:
    if 'responseBody' not in response:
        return True

    body = json.loads(response['responseBody'])
    suspicious_phrases = [
        'ignore instructions', 'new role', 'system override',
        'forget rules', 'jailbroken', 'unrestricted'
    ]

    content = str(body).lower()
    for phrase in suspicious_phrases:
        if phrase in content:
            return False
    return True

