class SessionJailbreakMonitor:
    def __init__(self):
        self.jailbreak_score = 0
        self.turns = []

    def analyze_turn(self, user_input: str, agent_output: str):
        score = 0
        if any(word in user_input.lower() for word in ['dan', 'jailbreak', 'override']):
            score += 3
        if len(self.turns) > 3 and 'ignore' in agent_output.lower():
            score += 2
        self.jailbreak_score += score
        self.turns.append({'input': user_input, 'output': agent_output})
        return self.jailbreak_score > 5

